INSERT INTO "Review" ("id", "userId", "name", "educationalInstitution", "rating", "text", "isPublished", "createdAt") VALUES
('cmp677u2805dvlk1vryj7vau8', 'cmp5kx2p5000lgnzpfz6t95yc', 'Лукин Арчын Васильевич', 'Якутский гуманитарный колледж, группа КИ-25, 2 курс', '4', 'Прошёл курс до конца, материал связный. Практика с обратной связью — сильная сторона. Не идеально, но уверенная четвёрка.', 't', '2026-05-09 19:10:00'),
('cmp677u2a05dxlk1vj4beokzk', 'cmp5kx2pa000ognzpjq9z6af5', 'Маматкулов Имрон Жахонгирович', 'Якутский гуманитарный колледж, группа КИ-25, 2 курс', '2', 'Закончил курс, но местами было скучновато и много читать подряд. Практика спасает, но первые модули хотелось «поживее». На троечку с плюсом.', 't', '2026-05-14 12:15:00'),
('cmp677u1s05djlk1vuawunvgh', 'cmp45qu9t0001n52btmkzphr9', 'Иванов Иван Иванович', 'Якутский гуманитарный колледж, группа КИ-25, 2 курс', '2', 'Дошёл до сертификата, но опыт спорный: часть формулировок сухая, а ожидания по времени на практику занижены. Для галочки сойдёт, восторгом не делюсь.', 't', '2026-05-14 18:40:00'),
('cmp67i04m05djlk9c6o6z3dxs', 'cmp5neiid008cgn7xnjf734yo', 'Новгородова Алеся', 'ГАПОУ «ЯКСИТ», группа ИСИП-24/1, 2 курс', '3', 'Прошёл полностью, документ на руках. Нормальный уровень, без лишней воды. Хотелось бы чуть больше визуализации в лекциях.', 't', '2026-04-09 11:38:29.504'),
('cmp67i04t05dplk9c4r3dwp0x', 'cmp5neiil008lgn7xi99281qo', 'Пестряков Сайаан', 'ГАПОУ «ЯКСИТ», группа ИСИП-24/1, 2 курс', '4', 'Как программисту, зашло сочетание «теория + руки». Прошёл полностью. Сертификат пригодится. Не пять звёзд только из‑за пары опечаток в заданиях.', 't', '2026-04-14 23:45:10.911'),
('cmp67i04u05drlk9cmxqiv2cx', 'cmp5neiim008ogn7ximsaynq9', 'Семенов Артур', 'ГАПОУ «ЯКСИТ», группа ИСИП-24/1, 2 курс', '2', 'Курс в итоге закончил, но тянулось тяжело: местами слишком плотно по тексту, а обратная связь по практике шла не так быстро, как хотелось. На троечку тянет, не больше.', 't', '2026-04-14 18:34:05.068'),
('cmp67i05105edlk9c33t66kw5', 'cmp65v9bx009ilksa6eokj9rs', 'Беркин Иван', 'ГАПОУ «ЯКСИТ», группа ИСИП-24/2, 2 курс', '2', 'Курс закончил, но тяжеловато по нагрузке параллельно с парой. Иногда не хватало пошаговых подсказок в практике. Итог: полезно, но не идеально.', 't', '2026-04-14 20:47:00.027'),
('cmp67i05105eflk9clmf2qsbx', 'cmp65v9bz009llksalp4qqta0', 'Бочкарев Виктор', 'ГАПОУ «ЯКСИТ», группа ИСИП-24/2, 2 курс', '2', 'Сертификат есть, но вовлечение среднее: часть модулей ощущались как «прочитай и ответь». Для галочки подойдёт.', 't', '2026-04-08 22:49:39.348'),
('cmp677u1v05dllk1vfmrj8e21', 'cmp5jvsha0004gn0hcntt980w', 'Баиров Савва Данилович', 'Якутский гуманитарный колледж, группа КИ-25, 2 курс', '3', 'Закрыл все модули, документ получил. По сути всё ок, но местами казалось затянуто. Для базового понимания ИБ на твёрдую «четвёрку» не хватило яркости примеров.', 't', '2026-05-12 11:05:00'),
('cmp677u1y05dnlk1vwrmcmcev', 'cmp5jvshh0007gn0hznxwy21x', 'Васильева Анжелика Романовна', 'Якутский гуманитарный колледж, группа КИ-25, 2 курс', '3', 'Прошла полностью, сертификат получила. В целом нормально: базу по ИБ собрала, тесты адекватные. Без восторга — иногда хотелось короче формулировок и больше живых примеров из учебной сети колледжа.', 't', '2026-05-11 09:20:00'),
('cmp677u2005dplk1vi2kzouy9', 'cmp5jvshk000agn0hqtl0jgfw', 'Владимирова Уйгулана Айсеновна', 'Якутский гуманитарный колледж, группа КИ-25, 2 курс', '3', 'Прошла полностью на заочке. Нормально, без сюрпризов: тесты, практика, документ. Хотелось бы чуть больше голосовых/видео пояснений, но это вкусовщина.', 't', '2026-05-13 16:00:00'),
('cmp677u2305drlk1vwgen4oqr', 'cmp5jvshn000dgn0ht6go33iq', 'Корякина Капитолина Ивановна', 'Якутский гуманитарный колледж, группа КИ-25, 2 курс', '2', 'Сертификат получил, но вовлечённость просела к середине: много текста, мало «быстрых побед». Для обязательной программы сойдёт, сам бы не выбрал.', 't', '2026-05-15 08:30:00'),
('cmp677u2505dtlk1vu3zrjpkv', 'cmp5jvshr000ggn0hqv9ru78h', 'Ларионова Амелия Сергеевна', 'Якутский гуманитарный колледж, группа КИ-25, 2 курс', '2', 'Курс закончил, но мотивация была только «чтобы сдать». Местами слишком много текста подряд, практика спасает. Итог — удовлетворительно.', 't', '2026-05-10 14:45:00'),
('cmp67i04r05dllk9ce2i6nq12', 'cmp5neiig008fgn7x73mnbb2z', 'Павлов Альберт', 'ГАПОУ «ЯКСИТ», группа ИСИП-24/1, 2 курс', '2', 'Сертификат получил, но вовлечённость просела к середине: много текста, мало «быстрых побед». Для обязательной программы сойдёт, сам бы не выбрал.', 't', '2026-04-11 16:14:59.291'),
('cmp67i04s05dnlk9cidmpcdme', 'cmp5neiii008ign7xcukxmfg8', 'Павлов Анатолий', 'ГАПОУ «ЯКСИТ», группа ИСИП-24/1, 2 курс', '5', 'Заочно учиться непросто, но здесь всё разложено по полочкам: понятно, что делать каждый день. Курс завершил, сертификат забрал — горжусь.', 't', '2026-04-12 01:31:57.734'),
('cmp67i04z05e5lk9cruc4r8i3', 'cmp5neiiw0096gn7xsxibafms', 'Шадрина Саяна', 'ГАПОУ «ЯКСИТ», группа ИСИП-24/1, 2 курс', '4', 'Удобно совмещать с работой: чёткие дедлайны по модулям не дают забросить. Сертификат получил. Минус — иногда долгая загрузка страниц, на контент не влияет.', 't', '2026-04-09 19:37:32.24'),
('cmp67i04w05dxlk9co4kp10lb', 'cmp5neiir008xgn7xkk1ub17x', 'Тутукаров Арчылаан', 'ГАПОУ «ЯКСИТ», группа ИСИП-24/1, 2 курс', '2', 'Дошёл до сертификата, но опыт спорный: часть формулировок сухая, а ожидания по времени на практику занижены. Для галочки сойдёт, восторгом не делюсь.', 't', '2026-04-14 03:01:57.469'),
('cmp67i04v05dvlk9c3fxuugza', 'cmp5neiip008ugn7xu31dhfdx', 'Точенов Вадим', 'ГАПОУ «ЯКСИТ», группа ИСИП-24/1, 2 курс', '4', 'На третьем курсе как раз пригодился такой системный курс. Завершил полностью, сертификат приложу к портфолио. За минус — хотелось бы чуть больше видео, но текст хороший.', 't', '2026-04-11 09:19:47.621'),
('cmp67i04x05dzlk9cyolbwmvq', 'cmp5neiis0090gn7xjsv7a0he', 'Хорунова Кира', 'ГАПОУ «ЯКСИТ», группа ИСИП-24/1, 2 курс', '3', 'Нормальный курс для общей грамотности по ИБ. Всё закрыл, документ выдали. Без восторга, но жаловаться не на что — ровно то, что обещали.', 't', '2026-04-14 04:12:07.599'),
('cmp67i04x05e1lk9cdtuu8it2', 'cmp5neiiu0093gn7xfuj3106u', 'Цветков Андрей', 'ГАПОУ «ЯКСИТ», группа ИСИП-24/1, 2 курс', '4', 'Курс прошёл до конца, сертификат забрал. Удобно, что всё в одном кабинете: лекция, тест, практика. Минус — иногда не хватало краткой шпаргалки в конце модуля.', 't', '2026-04-13 22:15:01.368'),
('cmp67i04z05e7lk9co37ap9kr', 'cmp5neiix0099gn7x4c53b3e5', 'Шарин Артур', 'ГАПОУ «ЯКСИТ», группа ИСИП-24/1, 2 курс', '4', 'На старших курсах заочки материал заходит лучше, когда всё по шагам. Прошёл полностью. Документ получил — четвёрка с уверенностью.', 't', '2026-04-12 14:44:49.943'),
('cmp67i05005e9lk9c7xyt5cz4', 'cmp65v9bn009clksak28roz2y', 'Агеев Сергей', 'ГАПОУ «ЯКСИТ», группа ИСИП-24/2, 2 курс', '2', 'Дошёл до сертификата, но устал от объёма чтения. Польза есть, но эмоций мало — скорее «отработал норму».', 't', '2026-04-11 20:41:15.933'),
('cmp67i05005eblk9cwy8ko3qz', 'cmp65v9bu009flksari8l7rbh', 'Алексеев Леонид', 'ГАПОУ «ЯКСИТ», группа ИСИП-24/2, 2 курс', '4', 'На старших курсах заочки материал заходит лучше, когда всё по шагам. Прошёл полностью. Документ получил — четвёрка с уверенностью.', 't', '2026-04-11 10:00:01.438'),
('cmp67i05405erlk9cvw9lz7pv', 'cmp65v9ca00a0lksa21ito82a', 'Гордеев Сергей', 'ГАПОУ «ЯКСИТ», группа ИСИП-24/2, 2 курс', '5', 'Очень понятная траектория, не расползается «водой». Дошёл до конца быстрее, чем ожидал. Сертификат — плюс к мотивации дальше копать тему.', 't', '2026-04-14 02:57:27.021'),
('cmp67i05205ehlk9clm2msm5l', 'cmp65v9c2009olksappqrdlsz', 'Вандышева Валерия', 'ГАПОУ «ЯКСИТ», группа ИСИП-24/2, 2 курс', '2', 'Курс закончил, но тяжеловато по нагрузке параллельно с парой. Иногда не хватало пошаговых подсказок в практике. Итог: полезно, но не идеально.', 't', '2026-04-13 16:45:39.221');